// Build a single LLM prompt with all context. Items come in via Merge.
// items[0]=Open AIs, items[1]=sent emails, items[2]=inbox, items[3]=Slack
const items = $input.all();
const openTasks = items[0] && items[0].json || {};
const sentEmails = items[1] && items[1].json || {};
const inboxEmails = items[2] && items[2].json || {};
const slack = items[3] && items[3].json || {};

// Format open AIs
function extractText(prop) {
  if (!prop) return '';
  if (prop.title) return prop.title.map(t => t.plain_text || '').join('');
  if (prop.rich_text) return prop.rich_text.map(t => t.plain_text || '').join('');
  return '';
}

const openAis = (openTasks.results || []).map(p => {
  const props = p.properties || {};
  return {
    id: p.id,
    task: extractText(props.Task),
    source: extractText(props.Source),
    notes: extractText(props.Notes).slice(0, 1500),
    status: (props.Status && props.Status.status && props.Status.status.name) || '',
    created: p.created_time,
    url: p.url,
  };
});

if (openAis.length === 0) {
  return [{ json: { skip: true, reason: 'no open AIs to evaluate' } }];
}

// Format email lists as just subject + ts (the LLM does the heavy lifting)
const sentList = (sentEmails.messages || []).slice(0, 20).map(m => ({ id: m.id, thread: m.threadId }));
const inboxList = (inboxEmails.messages || []).slice(0, 20).map(m => ({ id: m.id, thread: m.threadId }));
const slackMessages = (slack.messages && slack.messages.matches) || [];
const slackList = slackMessages.slice(0, 30).map(m => ({
  ts: m.ts,
  channel: (m.channel && m.channel.name) || (m.channel && m.channel.id) || '?',
  user: m.username || m.user || '?',
  text: (m.text || '').slice(0, 400),
  permalink: m.permalink,
}));

return [{ json: { openAis, sentList, inboxList, slackList } }];

// Build the LLM prompt. Email bodies are NOT fetched here to keep context small —
// the LLM only needs Slack text snippets + the open AIs themselves. Email signals
// will be added in v2 once we know which AIs need deeper email forensics.

if ($json.skip) return $json;

const { openAis, slackList } = $json;

const aisFormatted = openAis.map((a, i) => `[${i}] id=${a.id}\n  task: ${a.task}\n  source: ${a.source}\n  created: ${a.created}\n  notes: ${a.notes.slice(0, 600)}`).join('\n\n');

const slackFormatted = slackList.map(s => `[${s.ts.slice(0, 10)}] #${s.channel} from ${s.user}: ${s.text}`).join('\n');

const prompt = `You are evaluating which open action items (AIs) have been COMPLETED, based on recent activity.

Today's date: ${new Date().toISOString().slice(0, 10)}

OPEN ACTION ITEMS (${openAis.length}):

${aisFormatted}

---

RECENT SLACK ACTIVITY (last 7 days, ${slackList.length} messages):

${slackFormatted}

---

For each open AI, decide its status. Possible signals of completion:
- Sales User's outbound Slack message mentioning the deliverable as sent/done
- Owner's message confirming completion
- Subsequent message that supersedes or cancels the AI ("don't worry about it", "never mind")
- AI is now clearly stale or no longer relevant

IMPORTANT: only mark status="done" or "cancelled" if you have HIGH CONFIDENCE based on explicit evidence in the activity. Do NOT guess.

Return ONLY JSON:
{
  "evaluations": [
    {
      "ai_id": "<notion page id>",
      "status": "done" | "cancelled" | "open",
      "confidence": 0.0,
      "reason": "<one sentence justification>",
      "evidence": "<short quote or permalink, optional>"
    }
  ]
}

Only evaluations with status != "open" need to be high-quality. Items still open can be brief.
Only emit done/cancelled with confidence >= 0.7. Below that, leave as open.`;

return { openAis, prompt };

// Parse LLM, emit one item per AI that should be updated.
const input = $input.first().json;
const openAis = $('Build prompt').first().json.openAis || [];

let parsed = null;
let error = null;
try {
  const text = (input.content || []).map(c => c.text || '').join('');
  const m = text.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON in LLM response');
  parsed = JSON.parse(m[0]);
} catch (e) {
  error = e.message;
}

if (error || !parsed) {
  // Emit no items so Update node doesn't fire
  return [];
}

const evaluations = parsed.evaluations || [];
const statusMap = { done: 'Done', cancelled: 'Done', open: null };  // 'cancelled' also flips to Done for v1

const toUpdate = [];
for (const ev of evaluations) {
  const newStatus = statusMap[ev.status];
  if (!newStatus) continue;
  if (!ev.confidence || ev.confidence < 0.7) continue;
  toUpdate.push({
    ai_id: ev.ai_id,
    new_status: newStatus,
    confidence: ev.confidence,
    reason: ev.reason,
    evidence: ev.evidence,
    original_status_decision: ev.status,
  });
}

// Emit ONLY high-confidence closures; if none, emit nothing (Update Open Task won't fire)
return toUpdate.map(u => ({ json: u }));

// Aggregate: count actual closures applied (Update Open Task outputs),
// plus include the full LLM evaluation for transparency.
let updates = [];
try { updates = $('Update Open Task').all().map(i => i.json).filter(j => j && j.object === 'page'); } catch (e) { /* Update node didn't run */ }
const evaluationsText = (($('Anthropic evaluate').first().json.content || []).map(c => c.text || '').join(''));

let parsedEvals = null;
try {
  const m = evaluationsText.match(/\{[\s\S]*\}/);
  if (m) parsedEvals = JSON.parse(m[0]);
} catch (e) {}

const totalEvaluated = parsedEvals && parsedEvals.evaluations ? parsedEvals.evaluations.length : 0;
const closuresApplied = updates.length;

return { summary: { total_evaluated: totalEvaluated, closures_applied: closuresApplied, generated_at: new Date().toISOString() }, updates_applied: updates.map(u => ({ id: u.id, url: u.url })), raw_evaluations: parsedEvals };
